namespace sv_1548d8a4acdb45809aed189aad0488d1.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

namespace sv_1548d8a4acdb45809aed189aad0488d1.Services;

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

namespace sv_1548d8a4acdb45809aed189aad0488d1.Services;

public class MockChatService : IChatService
{
    private readonly List<Channel> _channels;
    private readonly List<Message> _messages;
    private int _nextMessageId = 100;

    public MockChatService()
    {
        _channels = new()
        {
            new(1, "general", "General discussion for the team", 3),
            new(2, "engineering", "Engineering updates and questions", 0),
            new(3, "design", "Design reviews and feedback", 1),
            new(4, "random", "Off-topic chat and fun stuff", 5),
            new(5, "announcements", "Important team announcements", 0),
        };

        var now = DateTime.UtcNow;
        _messages = new()
        {
            new(1, 1, "Alice", "Hey team! How's the new sprint going?", now.AddHours(-3), null, new() { new("👍", new() { "Bob", "Carol" }), new("🎉", new() { "Dave" }) }),
            new(2, 1, "Bob", "Going well! Just finished the auth module.", now.AddHours(-2.5), null, new()),
            new(3, 1, "Carol", "Nice work Bob! I have a question about the API design.", now.AddHours(-2), null, new() { new("👀", new() { "Alice" }) }),
            new(4, 1, "Dave", "Can we discuss the deployment plan?", now.AddHours(-1.5), null, new()),
            new(5, 1, "Alice", "Sure, let's set up a thread for that.", now.AddHours(-1), null, new()),
            new(6, 1, "Bob", "Sounds good. I'll share the architecture doc.", now.AddMinutes(-45), null, new() { new("👍", new() { "Alice", "Carol", "Dave" }) }),
            new(7, 1, "Carol", "Looking forward to it!", now.AddMinutes(-30), null, new()),
            new(8, 1, "Dave", "BTW, the staging environment is ready for testing.", now.AddMinutes(-15), null, new() { new("🚀", new() { "Alice", "Bob" }) }),
            new(9, 1, "Alice", "Great job everyone! Let's keep the momentum going.", now.AddMinutes(-5), null, new()),

            // Thread replies for message 1
            new(10, 1, "Bob", "Sprint is on track, we're ahead of schedule!", now.AddHours(-2.8), 1, new()),
            new(11, 1, "Carol", "Agreed, the planning session really helped.", now.AddHours(-2.6), 1, new()),
            new(12, 1, "Dave", "Let's keep it up!", now.AddHours(-2.4), 1, new()),

            // Thread replies for message 4
            new(13, 1, "Alice", "I think we should do a blue-green deployment.", now.AddHours(-1.2), 4, new()),
            new(14, 1, "Bob", "That makes sense for zero-downtime.", now.AddHours(-1.1), 4, new()),

            // Engineering channel messages
            new(20, 2, "Bob", "Pushed the new CI pipeline config.", now.AddHours(-4), null, new() { new("🎉", new() { "Alice" }) }),
            new(21, 2, "Alice", "Looks great! Build times dropped by 40%.", now.AddHours(-3.5), null, new()),
            new(22, 2, "Dave", "Can we add integration tests to the pipeline?", now.AddHours(-2), null, new()),

            // Design channel messages
            new(30, 3, "Carol", "New mockups for the dashboard are ready for review.", now.AddHours(-5), null, new() { new("👀", new() { "Alice", "Bob" }) }),
            new(31, 3, "Alice", "Love the color scheme! One suggestion on the nav.", now.AddHours(-4), null, new()),
        };
    }

    public Task<List<Channel>> GetChannelsAsync() =>
        Task.FromResult(_channels.ToList());

    public Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take)
    {
        var result = _messages
            .Where(m => m.ChannelId == channelId && m.ReplyToId == null)
            .OrderBy(m => m.SentAt)
            .Skip(skip)
            .Take(take)
            .ToList();
        return Task.FromResult(result);
    }

    public Task<Message> SendMessageAsync(int channelId, string content, int? replyToId)
    {
        var id = Interlocked.Increment(ref _nextMessageId);
        var message = new Message(id, channelId, "You", content, DateTime.UtcNow, replyToId, new());
        _messages.Add(message);
        return Task.FromResult(message);
    }

    public Task<List<Message>> GetThreadAsync(int rootMessageId)
    {
        var root = _messages.FirstOrDefault(m => m.Id == rootMessageId);
        var replies = _messages
            .Where(m => m.ReplyToId == rootMessageId)
            .OrderBy(m => m.SentAt)
            .ToList();

        var result = new List<Message>();
        if (root is not null) result.Add(root);
        result.AddRange(replies);
        return Task.FromResult(result);
    }

    public Task AddReactionAsync(int messageId, string emoji)
    {
        var msg = _messages.FirstOrDefault(m => m.Id == messageId);
        if (msg is not null)
        {
            var existing = msg.Reactions.FirstOrDefault(r => r.Emoji == emoji);
            if (existing is not null)
            {
                if (!existing.Users.Contains("You"))
                    existing.Users.Add("You");
            }
            else
            {
                msg.Reactions.Add(new Reaction(emoji, new() { "You" }));
            }
        }
        return Task.CompletedTask;
    }

    public Task MarkChannelReadAsync(int channelId)
    {
        var idx = _channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
            _channels[idx] = _channels[idx] with { UnreadCount = 0 };
        return Task.CompletedTask;
    }

    public int GetReplyCount(int rootMessageId) =>
        _messages.Count(m => m.ReplyToId == rootMessageId);
}

