@using sv_1548d8a4acdb45809aed189aad0488d1.Services

<div class="message-bubble p-2 rounded @(IsThreadRoot ? "thread-root" : "")"
     @onmouseenter="() => _showActions = true" @onmouseleave="HideActions">
    <div class="d-flex justify-content-between align-items-start">
        <div>
            <strong class="me-2">@Message.Author</strong>
            <small class="text-muted">@FormatRelativeTime(Message.SentAt)</small>
        </div>
        @if (_showActions)
        {
            <div class="message-actions d-flex gap-1">
                @if (!IsInThread)
                {
                    <button class="btn btn-sm btn-outline-secondary" @onclick="HandleReply" title="Reply in thread">
                        💬 Reply
                    </button>
                }
                <div class="position-relative">
                    <button class="btn btn-sm btn-outline-secondary" @onclick="ToggleEmojiPicker" title="Add reaction">
                        😀
                    </button>
                    @if (_showEmojiPicker)
                    {
                        <div class="position-absolute end-0" style="z-index: 10;">
                            <EmojiPicker OnEmojiSelected="HandleReaction" />
                        </div>
                    }
                </div>
            </div>
        }
    </div>
    <div class="message-content mt-1">@Message.Content</div>
    <ReactionBar Reactions="Message.Reactions" />
    @if (ReplyCount > 0 && !IsInThread)
    {
        <button class="btn btn-sm btn-link text-primary p-0 mt-1" @onclick="HandleReply">
            @ReplyCount @(ReplyCount == 1 ? "reply" : "replies")
        </button>
    }
</div>

@code {
    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public int ReplyCount { get; set; }
    [Parameter] public bool IsInThread { get; set; }
    [Parameter] public bool IsThreadRoot { get; set; }
    [Parameter] public EventCallback<int> OnReplyClicked { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReactionAdded { get; set; }

    private bool _showActions;
    private bool _showEmojiPicker;

    private Task HandleReply() => OnReplyClicked.InvokeAsync(Message.Id);

    private async Task HandleReaction(string emoji)
    {
        _showEmojiPicker = false;
        _showActions = false;
        await OnReactionAdded.InvokeAsync((Message.Id, emoji));
    }

    private void HideActions()
    {
        _showActions = false;
        _showEmojiPicker = false;
    }

    private void ToggleEmojiPicker() => _showEmojiPicker = !_showEmojiPicker;

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalMinutes < 1) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return sentAt.ToString("MMM d, h:mm tt");
    }
}

