@inject IJSRuntime JS

<div class="message-list flex-grow-1 overflow-auto p-3 d-flex flex-column" @ref="_scrollContainer" @onscroll="HandleScroll">
    @if (IsLoadingMore)
    {
        <div class="text-center py-2">
            <div class="spinner-border spinner-border-sm text-secondary" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    @foreach (var message in Messages)
    {
        <MessageBubble Message="message"
                       ReplyCount="GetReplyCount(message.Id)"
                       OnReplyClicked="OnOpenThread"
                       OnReactionAdded="OnReactionAdded" />
    }
</div>

@code {
    [Parameter, EditorRequired] public List<Message> Messages { get; set; } = new();
    [Parameter] public Dictionary<int, int> ReplyCounts { get; set; } = new();
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReactionAdded { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }

    private ElementReference _scrollContainer;

    private int GetReplyCount(int messageId) =>
        ReplyCounts.TryGetValue(messageId, out var count) ? count : 0;

    private async Task HandleScroll()
    {
        var scrollTop = await JS.InvokeAsync<double>("eval", "document.querySelector('.message-list')?.scrollTop ?? 1");
        if (scrollTop < 50)
        {
            await OnLoadMore.InvokeAsync();
        }
    }
}

