@inherits LayoutComponentBase

<div class="chat-layout vh-100 d-flex flex-column">
    @Body
</div>

@page "/chat"
@layout ChatLayout
@rendermode InteractiveServer
@using sv_1548d8a4acdb45809aed189aad0488d1.Services
@inject IChatService ChatService

<PageTitle>Team Chat</PageTitle>

<div class="chat-container d-flex flex-grow-1 overflow-hidden">
    <div class="chat-sidebar">
        <ChannelSidebar Channels="_channels"
                        SelectedChannelId="_selectedChannelId"
                        OnChannelSelected="HandleChannelSelected" />
    </div>

    <div class="chat-main @(_threadOpen ? "" : "chat-main-expanded")">
        <MessageArea Channel="_selectedChannel"
                     Messages="_messages"
                     ReplyCounts="_replyCounts"
                     IsLoadingMore="_isLoadingMore"
                     OnSendMessage="HandleSendMessage"
                     OnOpenThread="HandleOpenThread"
                     OnReactionAdded="HandleReaction"
                     OnLoadMore="HandleLoadMore" />
    </div>

    @if (_threadOpen)
    {
        <div class="chat-thread">
            <ThreadPanel RootMessage="_threadRoot"
                         Replies="_threadReplies"
                         OnClose="HandleCloseThread"
                         OnSendReply="HandleSendReply"
                         OnReactionAdded="HandleReaction" />
        </div>
    }
</div>

@code {
    private List<Channel> _channels = new();
    private List<Message> _messages = new();
    private Dictionary<int, int> _replyCounts = new();
    private Channel? _selectedChannel;
    private int _selectedChannelId;

    // Thread state
    private bool _threadOpen;
    private Message? _threadRoot;
    private List<Message> _threadReplies = new();
    private int _threadRootId;

    // Pagination
    private bool _isLoadingMore;
    private bool _hasMoreMessages = true;
    private const int PageSize = 50;

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
        if (_channels.Any())
        {
            await HandleChannelSelected(_channels.First().Id);
        }
    }

    private async Task HandleChannelSelected(int channelId)
    {
        _selectedChannelId = channelId;
        _selectedChannel = _channels.FirstOrDefault(c => c.Id == channelId);
        _hasMoreMessages = true;
        _threadOpen = false;

        _messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        await UpdateReplyCounts();
        await ChatService.MarkChannelReadAsync(channelId);

        // Refresh channel list to clear unread badge
        _channels = await ChatService.GetChannelsAsync();
    }

    private async Task HandleSendMessage(string content)
    {
        var message = await ChatService.SendMessageAsync(_selectedChannelId, content, null);
        _messages.Add(message);
    }

    private async Task HandleOpenThread(int rootMessageId)
    {
        _threadRootId = rootMessageId;
        var thread = await ChatService.GetThreadAsync(rootMessageId);
        _threadRoot = thread.FirstOrDefault();
        _threadReplies = thread.Skip(1).ToList();
        _threadOpen = true;
    }

    private async Task HandleCloseThread()
    {
        _threadOpen = false;
        _threadRoot = null;
        _threadReplies.Clear();
        await Task.CompletedTask;
    }

    private async Task HandleSendReply(string content)
    {
        var reply = await ChatService.SendMessageAsync(_selectedChannelId, content, _threadRootId);
        _threadReplies.Add(reply);
        await UpdateReplyCounts();
    }

    private async Task HandleReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Refresh messages to show updated reactions
        _messages = await ChatService.GetMessagesAsync(_selectedChannelId, 0, _messages.Count);

        // Refresh thread if open
        if (_threadOpen)
        {
            var thread = await ChatService.GetThreadAsync(_threadRootId);
            _threadRoot = thread.FirstOrDefault();
            _threadReplies = thread.Skip(1).ToList();
        }
    }

    private async Task HandleLoadMore()
    {
        if (_isLoadingMore || !_hasMoreMessages) return;
        _isLoadingMore = true;

        var older = await ChatService.GetMessagesAsync(_selectedChannelId, _messages.Count, PageSize);
        if (older.Count < PageSize)
            _hasMoreMessages = false;

        if (older.Any())
        {
            _messages.InsertRange(0, older);
            await UpdateReplyCounts();
        }

        _isLoadingMore = false;
    }

    private async Task UpdateReplyCounts()
    {
        _replyCounts.Clear();
        foreach (var msg in _messages)
        {
            var thread = await ChatService.GetThreadAsync(msg.Id);
            var replyCount = thread.Count - 1; // exclude root
            if (replyCount > 0)
                _replyCounts[msg.Id] = replyCount;
        }
    }
}

