arguments.file_text:
.chat-container {
    height: 100vh;
}

.chat-sidebar {
    width: 20%;
    min-width: 200px;
    max-width: 280px;
    border-right: 1px solid #dee2e6;
    background-color: #f8f9fa;
}

.chat-main {
    width: 55%;
    flex-grow: 1;
    min-width: 0;
}

.chat-main-expanded {
    width: 80%;
}

.chat-thread {
    width: 25%;
    min-width: 280px;
    max-width: 400px;
    background-color: #fff;
}

::deep .channel-item {
    padding: 0.5rem 0.75rem;
    cursor: pointer;
    border-left: 3px solid transparent;
    transition: background-color 0.15s;
}

::deep .channel-item:hover {
    background-color: #e9ecef;
}

::deep .channel-item.active {
    background-color: #e2e6ea;
    border-left-color: #0d6efd;
}

::deep .channel-name {
    font-weight: 600;
    font-size: 0.95rem;
}

::deep .channel-desc {
    font-size: 0.8rem;
    max-width: 180px;
}

::deep .message-bubble {
    margin-bottom: 0.75rem;
    padding: 0.5rem;
    border-radius: 0.375rem;
    transition: background-color 0.15s;
}

::deep .message-bubble:hover {
    background-color: #f8f9fa;
}

::deep .message-bubble.thread-root {
    background-color: #f0f4ff;
    border-left: 3px solid #0d6efd;
}

::deep .message-actions {
    opacity: 0;
    transition: opacity 0.15s;
}

::deep .message-bubble:hover .message-actions {
    opacity: 1;
}

::deep .reaction-badge {
    cursor: pointer;
    font-size: 0.8rem;
}

::deep .reaction-badge:hover {
    background-color: #e2e6ea !important;
}

::deep .emoji-picker {
    position: absolute;
    top: 100%;
    right: 0;
}

::deep .emoji-btn {
    font-size: 1.1rem;
    padding: 0.15rem 0.35rem;
    line-height: 1;
}

::deep .thread-panel {
    background-color: #fff;
}

::deep .thread-header {
    background-color: #f8f9fa;
}

::deep .thread-replies .message-bubble {
    margin-bottom: 0.5rem;
}

